/* NAMES */
export type Name = 'accept' | 'at' | 'behavior' | 'else' | 'feature' | 'frame' | 'function' | 'if' | 'interaction' | 'member' | 'metaclass' | 'multiplicity' | 'predicate' | 'snapshot' | 'step' | 'then' | 'type' | 'var' | 'via' | string;

export function isName(item: unknown): item is Name {
    return item === 'then' || item === 'else' || item === 'if' || item === 'accept' || item === 'via' || item === 'at' || item === 'frame' || item === 'snapshot' || item === 'var' || item === 'multiplicity' || item === 'type' || item === 'step' || item === 'member' || item === 'feature' || item === 'function' || item === 'predicate' || item === 'behavior' || item === 'interaction' || item === 'metaclass' || (typeof item === 'string' && (/((([a-z]|[A-Z])|_)((([a-z]|[A-Z])|_)|[0-9])*)/.test(item) || /('((\\(((((((b|t)|n)|f)|r)|")|')|\\))|((?!(\\|'))[\s\S]*?))*')/.test(item)));
}

